    def _set_process_priority(self, pid: int) -> None:
        """Best-effort attempt to set the priority of the editor process.

        Any failure (unsupported platform, insufficient permissions,
        unknown priority value, etc.) is silently ignored so that the
        edit operation always proceeds.
        """
        if self.process_priority is None:
            return

        if WIN:
            win_class = _WIN_PRIORITY_CLASSES.get(self.process_priority)
            if win_class is None:
                return
