            nice_value = _NICE_VALUES.get(self.process_priority)
            if nice_value is None:
                return
            try:
                os.setpriority(os.PRIO_PROCESS, pid, nice_value)  # type: ignore[attr-defined]
            except (AttributeError, OSError, PermissionError):
                pass

